CREATE TABLE IF NOT EXISTS sub_clos (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), clo_id UUID NOT NULL REFERENCES learning_outcomes(id) ON DELETE CASCADE, title TEXT NOT NULL, description TEXT, sort_order INTEGER DEFAULT 0, created_at TIMESTAMPTZ DEFAULT now()); ALTER TABLE sub_clos ENABLE ROW LEVEL SECURITY; CREATE TABLE IF NOT EXISTS study_sessions (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), student_id UUID NOT NULL REFERENCES profiles(id), course_id UUID REFERENCES courses(id), clo_id UUID REFERENCES learning_outcomes(id), session_type TEXT NOT NULL DEFAULT 'focus' CHECK (session_type IN ('focus','pomodoro','free','review')), planned_duration_minutes INTEGER, actual_duration_minutes INTEGER, intent TEXT, reflection TEXT, flow_rating INTEGER CHECK (flow_rating BETWEEN 1 AND 5), started_at TIMESTAMPTZ NOT NULL, ended_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT now()); ALTER TABLE study_sessions ENABLE ROW LEVEL SECURITY; CREATE TABLE IF NOT EXISTS planner_tasks (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), student_id UUID NOT NULL REFERENCES profiles(id), title TEXT NOT NULL, description TEXT, due_date DATE, priority TEXT DEFAULT 'medium' CHECK (priority IN ('low','medium','high')), status TEXT DEFAULT 'todo' CHECK (status IN ('todo','in_progress','done','deferred')), assignment_id UUID REFERENCES assignments(id), clo_id UUID REFERENCES learning_outcomes(id), planned_date DATE, sort_order INTEGER DEFAULT 0, created_at TIMESTAMPTZ DEFAULT now()); ALTER TABLE planner_tasks ENABLE ROW LEVEL SECURITY; CREATE TABLE IF NOT EXISTS weekly_goals (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), student_id UUID NOT NULL REFERENCES profiles(id), week_start DATE NOT NULL, goal_text TEXT NOT NULL, target_value NUMERIC, current_value NUMERIC DEFAULT 0, goal_type TEXT DEFAULT 'custom', status TEXT DEFAULT 'active' CHECK (status IN ('active','completed','abandoned')), created_at TIMESTAMPTZ DEFAULT now()); ALTER TABLE weekly_goals ENABLE ROW LEVEL SECURITY; CREATE TABLE IF NOT EXISTS session_evidence (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), session_id UUID NOT NULL REFERENCES study_sessions(id) ON DELETE CASCADE, evidence_type TEXT NOT NULL CHECK (evidence_type IN ('note','screenshot','file','link')), content TEXT, file_url TEXT, created_at TIMESTAMPTZ DEFAULT now()); ALTER TABLE session_evidence ENABLE ROW LEVEL SECURITY; CREATE TABLE IF NOT EXISTS habit_correlations (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), student_id UUID NOT NULL REFERENCES profiles(id), habit_type TEXT NOT NULL, correlated_metric TEXT NOT NULL, correlation_coefficient NUMERIC, sample_size INTEGER, computed_at TIMESTAMPTZ DEFAULT now()); ALTER TABLE habit_correlations ENABLE ROW LEVEL SECURITY; CREATE POLICY "sub_clos_select" ON sub_clos FOR SELECT TO authenticated USING (true); CREATE POLICY "sub_clos_manage" ON sub_clos FOR ALL TO authenticated USING (true); CREATE POLICY "study_sessions_own" ON study_sessions FOR ALL TO authenticated USING (student_id = auth.uid()); CREATE POLICY "planner_tasks_own" ON planner_tasks FOR ALL TO authenticated USING (student_id = auth.uid()); CREATE POLICY "weekly_goals_own" ON weekly_goals FOR ALL TO authenticated USING (student_id = auth.uid()); CREATE POLICY "session_evidence_own" ON session_evidence FOR ALL TO authenticated USING (EXISTS (SELECT 1 FROM study_sessions s WHERE s.id = session_id AND s.student_id = auth.uid())); CREATE POLICY "habit_correlations_own" ON habit_correlations FOR ALL TO authenticated USING (student_id = auth.uid());;
